import{_ as e,o as r,c as a,ag as n}from"./chunks/framework.DXGyWiRo.js";const o="/images/lekt4602.jpg",i="/images/lekt4603.jpg",l="/images/lekt4604.jpg",d="/images/lekt4605.jpg",s="/images/lekt4607.jpg",h="/images/lekt4606.jpg",b="/images/lekt4608.jpg",u="/images/lekt4609.jpg",p="/images/lekt4610.jpg",c="/images/lekt4601.jpg",m="/images/lekt4611.jpg",k="/images/lekt4612.jpg",I=JSON.parse('{"title":"Lektion 46","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/lektion46.md","filePath":"lektionen/lektion46.md"}'),f={name:"lektionen/lektion46.md"};function g(q,t,P,y,w,_){return r(),a("div",null,[...t[0]||(t[0]=[n('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="lektion-46" tabindex="-1">Lektion 46 <a class="header-anchor" href="#lektion-46" aria-label="Permalink to &quot;Lektion 46&quot;">​</a></h1><h2 id="ubersicht" tabindex="-1">Übersicht <a class="header-anchor" href="#ubersicht" aria-label="Permalink to &quot;Übersicht&quot;">​</a></h2><ul><li>46.1. Bildung der Verbalformen der 2. Person (मध्यमः) Perfekt (लिट्) <ul><li>46.1.1. Endungen</li><li>46.1.2. Lautveränderung der Endung -dhve</li><li>46.1.3. Perfekt Typ I: keine Stammabstufung</li><li>46.1.4. Perfekt Typ II: starker Stamm Hochstufe, schwacher Stamm Tiefstufe</li><li>46.1.5. Perfekt Typ III: Starker Stamm Hochstufe/Dehnstufe <ul><li>46.1.5.1. Perfekt Typ IIIa: Starker Stamm Hochstufe/Dehnstufe, schwacher Stamm Tiefstufe</li><li>46.1.5.2. Perfekt Typ IIIb: Starker Stamm Hochstufe/Dehnstufe, schwacher Stamm Hochstufe</li></ul></li><li>46.1.6. Perfekt Typ IV: Wurzeln auf -ā / -ai</li><li>46.1.7. Perfekt Typ V: Konsonant-a-Konsonant <ul><li>46.1.7.1. Perfekt Typ Va: Konsonant-a-Konsonant, schwacher Stamm Tiefstufe</li><li>46.1.7.2. Perfekt Typ Vb: Konsonant-a-Konsonant, Anfangskonsonant kein Guttural, Aspirat, h, Schwacher Stamm ohne Reduplikation, mit -e-</li><li>46.1.7.3. Perfekt Typ Vc: Konsonant-a-Konsonant, schwacher Stamm Hochstufe</li></ul></li><li>46.1.8. Besondere Perfekt-Bildungen</li><li>46.1.9. Periphrastisches Perfekt (अनुप्रयोगलिट्)</li></ul></li><li>46.2. Wortliste</li><li>46.3. Übung</li></ul><h2 id="_46-1-bildung-der-verbalformen-der-2-person-मध्यमः-perfekt-लिट्" tabindex="-1">46.1. Bildung der Verbalformen der 2. Person (मध्यमः) Perfekt (लिट्) <a class="header-anchor" href="#_46-1-bildung-der-verbalformen-der-2-person-मध्यमः-perfekt-लिट्" aria-label="Permalink to &quot;46.1. Bildung der Verbalformen der 2. Person (मध्यमः) Perfekt (लिट्)&quot;">​</a></h2><h3 id="_46-1-1-endungen" tabindex="-1">46.1.1. Endungen <a class="header-anchor" href="#_46-1-1-endungen" aria-label="Permalink to &quot;46.1.1. Endungen&quot;">​</a></h3><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td></td><td>एकवचनम्</td><td>बहुवचनम्</td></tr><tr><td>Perfektendungen</td><td>-tha</td><td>-a</td></tr></tbody></table><p>Beachten Sie, dass die Endung -- meistens aber nicht die Form! -- der 2.pl.P mit der der 1. und 3.sg.P übereinstimmt.</p><p>Vor -tha tritt bei den meisten Wurzeln auf -ṛ kein Bindevokal -i-. Bei manchen Wurzeln ist vor -tha das -i- fakultativ.</p><h3 id="_46-1-2-lautveranderung-der-endung-dhve" tabindex="-1">46.1.2. Lautveränderung der Endung -dhve <a class="header-anchor" href="#_46-1-2-lautveranderung-der-endung-dhve" aria-label="Permalink to &quot;46.1.2. Lautveränderung der Endung -dhve&quot;">​</a></h3><p>Die Endung -dhve muss im Perfekt durch -ḍhve ersetzt werden, wenn ein wurzelhaftes -u oder -ṛ unmittelbar vorangeht. Diese Ersetzung kann wahlweise nach dem Bindevokal -i- erfolgen, wenn diesem ein Halbvokal oder h unmittelbar vorangeht.</p><h3 id="_46-1-3-perfekt-typ-i-keine-stammabstufung" tabindex="-1">46.1.3. Perfekt Typ I: keine Stammabstufung <a class="header-anchor" href="#_46-1-3-perfekt-typ-i-keine-stammabstufung" aria-label="Permalink to &quot;46.1.3. Perfekt Typ I: keine Stammabstufung&quot;">​</a></h3><p>Verben, die diesem Typ folgen:</p><ul><li>Konsonant-Langvokal-Konsonant</li><li>Konsonant-Vokal-Konsonant-Konsonant</li><li>a-Konsonant(-Konsonant)</li><li>ā-Konsonant</li></ul><p>1.sg.P = 3.sg.P = 2.pl.P</p><p>बन्ध् 9P</p><blockquote><table tabindex="0"><thead><tr><th>परस्मैपदम्</th></tr></thead><tbody><tr><td>एकवचनम्</td></tr><tr><td>बबन्धिथ</td></tr><tr><td>बबन्द्ध</td></tr></tbody></table></blockquote><p>जीव् 1P</p><blockquote><table tabindex="0"><thead><tr><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td>एकवचनम्</td><td>बहुवचनम्</td></tr><tr><td>जिजीविथ</td><td>जिजीव</td></tr><tr><td>&lt;जिजीविढ्वे&gt;</td><td></td></tr></tbody></table></blockquote><p>अस् 2P, 4P</p><blockquote><table tabindex="0"><thead><tr><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td>एकवचनम्</td><td>बहुवचनम्</td></tr><tr><td>आसिथ</td><td>आस</td></tr></tbody></table></blockquote><h3 id="_46-1-4-perfekt-typ-ii-starker-stamm-hochstufe-schwacher-stamm-tiefstufe" tabindex="-1">46.1.4. Perfekt Typ II: starker Stamm Hochstufe, schwacher Stamm Tiefstufe <a class="header-anchor" href="#_46-1-4-perfekt-typ-ii-starker-stamm-hochstufe-schwacher-stamm-tiefstufe" aria-label="Permalink to &quot;46.1.4. Perfekt Typ II: starker Stamm Hochstufe, schwacher Stamm Tiefstufe&quot;">​</a></h3><p>Verben, die diesem Typ folgen:</p><ul><li>(Konsonant-)i/u/ṛ/ḷ-Konsonant</li></ul><p>भिद् 7U</p><blockquote><table tabindex="0"><thead><tr><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td>एकवचनम्</td><td>बहुवचनम्</td></tr><tr><td>बिभेदिथ</td><td>बिभिद</td></tr></tbody></table></blockquote><p>मुह् 4P fakultativ अनिट्</p><blockquote><table tabindex="0"><thead><tr><th>परस्मैपदम्</th></tr></thead><tbody><tr><td>एकवचनम्</td></tr><tr><td>मुमोहिथ</td></tr><tr><td>मुमोढ</td></tr><tr><td>मुमोग्ध</td></tr></tbody></table></blockquote><h3 id="_46-1-5-perfekt-typ-iii-starker-stamm-hochstufe-dehnstufe" tabindex="-1">46.1.5. Perfekt Typ III: Starker Stamm Hochstufe/Dehnstufe <a class="header-anchor" href="#_46-1-5-perfekt-typ-iii-starker-stamm-hochstufe-dehnstufe" aria-label="Permalink to &quot;46.1.5. Perfekt Typ III: Starker Stamm Hochstufe/Dehnstufe&quot;">​</a></h3><h4 id="_46-1-5-1-perfekt-typ-iiia-starker-stamm-hochstufe-dehnstufe-schwacher-stamm-tiefstufe" tabindex="-1">46.1.5.1. Perfekt Typ IIIa: Starker Stamm Hochstufe/Dehnstufe, schwacher Stamm Tiefstufe <a class="header-anchor" href="#_46-1-5-1-perfekt-typ-iiia-starker-stamm-hochstufe-dehnstufe-schwacher-stamm-tiefstufe" aria-label="Permalink to &quot;46.1.5.1. Perfekt Typ IIIa: Starker Stamm Hochstufe/Dehnstufe, schwacher Stamm Tiefstufe&quot;">​</a></h4><p>Verben, die diesem Typ folgen:</p><ul><li>(Konsonant-)(Konsonant-)i/ī/u/ū</li><li>(Konsonant-)-ṛ</li></ul><p>इ 2P</p><blockquote><table tabindex="0"><thead><tr><th>परस्मैपदम्</th></tr></thead><tbody><tr><td>एकवचनम्</td></tr><tr><td>इयेथ</td></tr><tr><td>इययिथ</td></tr><tr><td>iy-e + i-tha</td></tr><tr><td>i + iy-a</td></tr></tbody></table></blockquote><p>नी 2U</p><blockquote><table tabindex="0"><thead><tr><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td>एकवचनम्</td><td>बहुवचनम्</td></tr><tr><td>निनयिथ</td><td></td></tr><tr><td>निनेथ</td><td>निन्य</td></tr><tr><td>ninī + a</td><td>निन्यिषे</td></tr><tr><td>निन्यिढ्वे</td><td></td></tr></tbody></table></blockquote><p>स्तु 2U (अनिट्)</p><blockquote><table tabindex="0"><thead><tr><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td>एकवचनम्</td><td>बहुवचनम्</td></tr><tr><td>तुष्टोथ</td><td>तिष्टुव</td></tr></tbody></table></blockquote><p>कृ 8U (अनिट्)</p><blockquote><table tabindex="0"><thead><tr><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td>एकवचनम्</td><td>बहुवचनम्</td></tr><tr><td>चकर्थ</td><td>चक्र</td></tr></tbody></table></blockquote><h4 id="_46-1-5-2-perfekt-typ-iiib-starker-stamm-hochstufe-dehnstufe-schwacher-stamm-hochstufe" tabindex="-1">46.1.5.2. Perfekt Typ IIIb: Starker Stamm Hochstufe/Dehnstufe, schwacher Stamm Hochstufe <a class="header-anchor" href="#_46-1-5-2-perfekt-typ-iiib-starker-stamm-hochstufe-dehnstufe-schwacher-stamm-hochstufe" aria-label="Permalink to &quot;46.1.5.2. Perfekt Typ IIIb: Starker Stamm Hochstufe/Dehnstufe, schwacher Stamm Hochstufe&quot;">​</a></h4><p>Verben, die diesem Typ folgen:</p><ul><li>(Konsonant-)(Konsonant-)-ṝ</li><li>Konsonant-Konsonant-ṛ</li></ul><p>पॄ 3P</p><blockquote><table tabindex="0"><thead><tr><th>परस्मैपदम्</th></tr></thead><tbody><tr><td>एकवचनम्</td></tr><tr><td>पपरिथ</td></tr><tr><td>= 1.sg.P</td></tr></tbody></table></blockquote><p>संस्कृ 8U</p><blockquote><table tabindex="0"><thead><tr><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td>एकवचनम्</td><td>बहुवचनम्</td></tr><tr><td>सञ्चस्करिथ</td><td>सञ्चस्कर</td></tr><tr><td>सञ्चसक्रिढ्वे</td><td></td></tr></tbody></table></blockquote><h3 id="_46-1-6-perfekt-typ-iv-wurzeln-auf-a-ai" tabindex="-1">46.1.6. Perfekt Typ IV: Wurzeln auf -ā / -ai <a class="header-anchor" href="#_46-1-6-perfekt-typ-iv-wurzeln-auf-a-ai" aria-label="Permalink to &quot;46.1.6. Perfekt Typ IV: Wurzeln auf -ā / -ai&quot;">​</a></h3><ul><li>Schwacher Stamm: <ul><li>vor Konsonant: Tiefstufe-i</li><li>vor Vokal: Tiefstufe-ø</li></ul></li></ul><p>दा 3U</p><blockquote><table tabindex="0"><thead><tr><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td>एकवचनम्</td><td>बहुवचनम्</td></tr><tr><td>ददाथ</td><td></td></tr><tr><td>ददिथ</td><td></td></tr><tr><td>da-di-tha</td><td></td></tr><tr><td>oder:</td><td></td></tr><tr><td>da-d-i-tha</td><td>दद</td></tr></tbody></table></blockquote><p>गै 1P</p><blockquote><table tabindex="0"><thead><tr><th>परस्मैपदम्</th></tr></thead><tbody><tr><td>एकवचनम्</td></tr><tr><td>जगाथ</td></tr><tr><td>जगिथ</td></tr></tbody></table></blockquote><h3 id="_46-1-7-perfekt-typ-v-konsonant-a-konsonant" tabindex="-1">46.1.7. Perfekt Typ V: Konsonant-a-Konsonant <a class="header-anchor" href="#_46-1-7-perfekt-typ-v-konsonant-a-konsonant" aria-label="Permalink to &quot;46.1.7. Perfekt Typ V: Konsonant-a-Konsonant&quot;">​</a></h3><h4 id="_46-1-7-1-perfekt-typ-va-konsonant-a-konsonant-schwacher-stamm-tiefstufe" tabindex="-1">46.1.7.1. Perfekt Typ Va: Konsonant-a-Konsonant, schwacher Stamm Tiefstufe <a class="header-anchor" href="#_46-1-7-1-perfekt-typ-va-konsonant-a-konsonant-schwacher-stamm-tiefstufe" aria-label="Permalink to &quot;46.1.7.1. Perfekt Typ Va: Konsonant-a-Konsonant, schwacher Stamm Tiefstufe&quot;">​</a></h4><p>Verben, die diesem Typ folgen:</p><blockquote><ol><li>gam &quot;gehen&quot;</li><li>han (»ghan) &quot;erschlagen&quot;</li><li>jan &quot;geboren werden&quot;</li><li>vac &quot;sprechen&quot;</li><li>vad &quot;sprechen&quot;</li><li>yaj &quot;opfern&quot;</li><li>u.a.</li></ol></blockquote><p>गम् 1P</p><blockquote><table tabindex="0"><thead><tr><th>परस्मैपदम्</th></tr></thead><tbody><tr><td>एकवचनम्</td></tr><tr><td>जगमिथ</td></tr><tr><td>जगन्थ</td></tr></tbody></table></blockquote><p>हन् 2P</p><blockquote><table tabindex="0"><thead><tr><th>परस्मैपदम्</th></tr></thead><tbody><tr><td>एकवचनम्</td></tr><tr><td>जघनित</td></tr><tr><td>जगन्थ</td></tr></tbody></table></blockquote><p>जन् 4Ā</p><blockquote><table tabindex="0"><thead><tr><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td>एकवचनम्</td></tr><tr><td>जज्ञिषे</td></tr></tbody></table></blockquote><p>यज् 1U</p><blockquote><table tabindex="0"><thead><tr><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td>एकवचनम्</td><td>बहुवचनम्</td></tr><tr><td>इयजिथ</td><td></td></tr><tr><td>इयष्ठ</td><td>ईज</td></tr></tbody></table></blockquote><p>वच् 1P</p><blockquote><table tabindex="0"><thead><tr><th>परस्मैपदम्</th></tr></thead><tbody><tr><td>एकवचनम्</td></tr><tr><td>उवचिथ</td></tr><tr><td>उवक्थ</td></tr></tbody></table></blockquote><p>वह् 1U</p><blockquote><table tabindex="0"><thead><tr><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td>एकवचनम्</td><td>बहुवचनम्</td></tr><tr><td>उवहिथ</td><td></td></tr><tr><td>उवोढ</td><td>ऊह</td></tr><tr><td>ऊहिढ्वे</td><td></td></tr></tbody></table></blockquote><p>वद् 1P</p><blockquote><table tabindex="0"><thead><tr><th>परस्मैपदम्</th></tr></thead><tbody><tr><td>एकवचनम्</td></tr><tr><td>उवदिथ</td></tr></tbody></table></blockquote><p>स्वप् 2P</p><blockquote><table tabindex="0"><thead><tr><th>परस्मैपदम्</th></tr></thead><tbody><tr><td>एकवचनम्</td></tr><tr><td>सुष्वपिथ</td></tr><tr><td>सुष्वप्थ</td></tr><tr><td>aus: su + *svp + a</td></tr></tbody></table></blockquote><h4 id="_46-1-7-2-perfekt-typ-vb-konsonant-a-konsonant-anfangskonsonant-kein-guttural-aspirat-h-schwacher-stamm-ohne-reduplikation-mit-e" tabindex="-1">46.1.7.2. Perfekt Typ Vb: Konsonant-a-Konsonant, Anfangskonsonant kein Guttural, Aspirat, h, Schwacher Stamm ohne Reduplikation, mit -e- <a class="header-anchor" href="#_46-1-7-2-perfekt-typ-vb-konsonant-a-konsonant-anfangskonsonant-kein-guttural-aspirat-h-schwacher-stamm-ohne-reduplikation-mit-e" aria-label="Permalink to &quot;46.1.7.2. Perfekt Typ Vb: Konsonant-a-Konsonant, Anfangskonsonant kein Guttural, Aspirat, h, Schwacher Stamm ohne Reduplikation, mit -e-&quot;">​</a></h4><p>Die 2.sg.P. wird vom schwachen Stamm gebildet, wenn der Bindevokal -i- antritt.</p><p>पच् 1U</p><blockquote><table tabindex="0"><thead><tr><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td>एकवचनम्</td><td>बहुवचनम्</td></tr><tr><td>पपक्थ</td><td></td></tr><tr><td>पेचिथ</td><td>पेच</td></tr></tbody></table></blockquote><h4 id="_46-1-7-3-perfekt-typ-vc-konsonant-a-konsonant-schwacher-stamm-hochstufe" tabindex="-1">46.1.7.3. Perfekt Typ Vc: Konsonant-a-Konsonant, schwacher Stamm Hochstufe <a class="header-anchor" href="#_46-1-7-3-perfekt-typ-vc-konsonant-a-konsonant-schwacher-stamm-hochstufe" aria-label="Permalink to &quot;46.1.7.3. Perfekt Typ Vc: Konsonant-a-Konsonant, schwacher Stamm Hochstufe&quot;">​</a></h4><p>Verben, die diesem Typ folgen:</p><ul><li>Alle übrigen Wurzeln mit mittlerem -a-</li></ul><p>क्रम् 1U</p><blockquote><table tabindex="0"><thead><tr><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td>एकवचनम्</td><td>बहुवचनम्</td></tr><tr><td>चक्रमिथ</td><td>चक्रम</td></tr></tbody></table></blockquote><h3 id="_46-1-8-besondere-perfekt-bildungen" tabindex="-1">46.1.8. Besondere Perfekt-Bildungen <a class="header-anchor" href="#_46-1-8-besondere-perfekt-bildungen" aria-label="Permalink to &quot;46.1.8. Besondere Perfekt-Bildungen&quot;">​</a></h3><p>विद् 2P präsentisches Perfekt</p><blockquote><table tabindex="0"><thead><tr><th>परस्मैपदम्</th></tr></thead><tbody><tr><td>एकवचनम्</td></tr><tr><td>वेत्थ</td></tr></tbody></table></blockquote><p>अह्</p><blockquote><table tabindex="0"><thead><tr><th>परस्मैपदम्</th></tr></thead><tbody><tr><td>एकवचनम्</td></tr><tr><td>आत्थ</td></tr></tbody></table></blockquote><p>भू 1P</p><blockquote><table tabindex="0"><thead><tr><th>परस्मैपदम्</th></tr></thead><tbody><tr><td>एकवचनम्</td></tr><tr><td>बभूविथ</td></tr><tr><td>= 1.3.sg.P</td></tr></tbody></table></blockquote><p>जि 1P</p><blockquote><table tabindex="0"><thead><tr><th>परस्मैपदम्</th></tr></thead><tbody><tr><td>एकवचनम्</td></tr><tr><td>जिगेथ</td></tr><tr><td>जिगयिथ</td></tr></tbody></table></blockquote><h3 id="_46-1-9-periphrastisches-perfekt-अनुप्रयोगलिट्" tabindex="-1">46.1.9. Periphrastisches Perfekt (अनुप्रयोगलिट्) <a class="header-anchor" href="#_46-1-9-periphrastisches-perfekt-अनुप्रयोगलिट्" aria-label="Permalink to &quot;46.1.9. Periphrastisches Perfekt (अनुप्रयोगलिट्)&quot;">​</a></h3><p>Das periphrastische Perfekt wird gebildet von:</p><ul><li>abgeleiteten Verbalstämme (Kausativ, Desiderativ, Frequentativ, Denominativa), insbesondere Kausativ</li><li>Wurzeln, die mit langem Vokal (außer ā) beginnen</li><li>Wurzeln: Vokal (außer a-)-Konsonant-Konsonant</li><li>einigen anderen</li><li>bei einigen Wurzeln können beide Perfekte optionell gebildet werden: uṣ &quot;brennen&quot;, vid &quot;wissen&quot;, jāgṛ &quot;wachen&quot;, daridrā &quot;arm sein&quot;</li><li>bei folgende Wurzeln  können beide Perfekte optionell gebildet werden und auch das periphrastische Perfekt ist redupliziert, und zwar mit der Reduplikationssilbe des Präsensstamms: <ul><li>bhī &quot;sich fürchten&quot;</li><li>bhṛ &quot;tragen&quot;</li><li>hu &quot;opfern&quot;</li><li>hrī &quot;sich schämen&quot;</li></ul></li></ul><p>बन्ध् Kausativ</p><blockquote><table tabindex="0"><thead><tr><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td>एकवचनम्</td><td>बहुवचनम्</td></tr><tr><td>बन्धयां चकर्थ</td><td></td></tr><tr><td>बन्धयामासिथ</td><td></td></tr><tr><td>बन्धयां बभूविथ</td><td>बन्धयां चक्र</td></tr><tr><td>बन्धयामास</td><td></td></tr><tr><td>बन्धयां बभूव</td><td>बन्धयां चकृषे</td></tr><tr><td>बन्धयामासिथ</td><td></td></tr><tr><td>बन्धयां बभूविथ</td><td>बन्धयां चकृढ्वे</td></tr><tr><td>बन्धयामास</td><td></td></tr><tr><td>बन्धयां बभूव</td><td></td></tr></tbody></table></blockquote><h2 id="_46-2-wortliste" tabindex="-1">46.2. Wortliste <a class="header-anchor" href="#_46-2-wortliste" aria-label="Permalink to &quot;46.2. Wortliste&quot;">​</a></h2><p>सम 3: gleich, eben, ähnlich</p><blockquote><p>davon:</p><p>समम् Adv.: in gleicher Weise, zugleich (तृतीयया), gleichmäßig</p><p>समता f.: Gleichmut</p><p>विषम 3: ungleich, uneben, böse</p></blockquote><p>ग्रह् 9U गृह्णाति (gṛh-ṇā-ti) : ergreifen, packen, fassen</p><blockquote><p>Perf Va (!) जग्राह, जगृहुर्<br> Fut. ग्रहीष्यति<br> Pass. गृह्यते<br> Kaus.ग्राहयति<br> PPP गृहीत<br> Inf. ग्रहितुम्<br> Absol. -ग्राह्य</p><p>davon:</p><p>ग्रह m.: Greifen, Greifer, Krokodil, Wandelstern</p><p>नवग्रह m.: die neun Wandelsterne (nicht Planeten!) (s. Basham, Wonder S. 493):</p><ol><li>सूर्यः = Sonne</li><li>चन्द्रः = Mond</li><li>मङ्गलः = Mars</li><li>बुधः = Merkur</li><li>बृहस्पतिः = Jupiter</li><li>शुक्रः = Venus</li><li>शनिः = Saturn</li><li>राहुः</li><li>केतुः</li></ol><p>Zu राहु und केतु siehe:</p><blockquote><p><strong>Payer, Alois &lt;1944 - &gt;:</strong> Dharmashastra : Einführung und Überblick. -- 10. Sakramente und Übergangsriten (samskara). -- Anhang C: Rahu und Ketu, die unsichtbaren Wandelsterne . -- URL: <a href="http://www.payer.de/dharmashastra/dharmash10c.htm" target="_blank" rel="noreferrer">http://www.payer.de/dharmashastra/dharmash10c.htm</a></p></blockquote></blockquote><p><img src="'+o+'" alt=""><br> सूर्यः = Sonne, चन्द्रः = Mond, मङ्गलः = Mars<br><img src="'+i+'" alt=""><br> बुधः = Merkur, बृहस्पतिः = Jupiter</p><p><img src="'+l+'" alt=""><br> शुक्रः = Venus, शनिः = Saturn<br><img src="'+d+'" alt=""><br> राहुः, केतुः<br> [Bildquelle der नवग्रह : Redtigerxyz / Wikipedia. GNU FDLicense]</p><p>तुष् 4P तुष्यति : sich zufrieden geben, zufrieden sein mit (षष्ठ्या, चतुर्थ्या, तृतियया, सप्तम्या)</p><blockquote><p>Perf. II तुतोष, तुतुषुर्<br> Fut. तोक्ष्यति<br> Pass. तुष्यते<br> Kaus. तोषयति<br> PPP तुष्ट<br> Inf. तोष्टुम्</p></blockquote><p>नम् 1P नमति : sich beugen, sich verbeugen, sich neigen, sich verneigen</p><blockquote><p>Perf. Vb ननाम, नेमुर्<br> Fut. नंस्यति<br> Pass. नम्यते<br> Kaus. नमयति । नामयति<br> PPP नत<br> Inf. नन्तुम्</p></blockquote><p><img src="'+s+'" alt=""><br> Abb.: नारायण तुभ्यं नमामि<br> नारायनो ऽनन्तशयी, ca. 1870 (अनन्त = शेष = oberster Schlangenkönig)<br> [Bildquelle: Wikipedia. Public domain]</p><p>रुह् 1P रोहति : ersteigen, besteigen</p><blockquote><p>Perf. II रुरोह, रुरुहे<br> Fut. रोक्ष्यति<br> Pass. रुह्यते<br> Kaus. रोहयति । रोपयति<br> PPP. रूढ<br> Inf. रोढुम्</p></blockquote><p><img src="'+h+'" alt=""><br> Abb.: अश्वरोहकः (अश्व m. &quot;Pferd&quot;)<br> Pune = पुणे<br> [Bildquelle: wili_hybrid. -- <a href="http://www.flickr.com/photos/wili/294411828/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/wili/294411828/</a>. -- Zugriff am 2009-01-08. -- <a href="http://creativecommons.org/licenses/by/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung)]</p><p>ह्वे । हू 1U ह्वयति : rufen, herbeirufen</p><blockquote><p>Perf. IIIa जुहाव, जुहुवे<br> Fut. ह्वास्यति<br> Pass. हूयते<br> Kaus. ह्वाययति<br> PPP हूत<br> Inf. ह्वातुम्<br> Absol. -हूय</p></blockquote><p><img src="'+b+'" alt=""><br> Abb.: महामात्र कं चरिष्णुदूरशब्देनाह्वयसि1<br> उदयपुर<br> [Bildquelle: Travel Aficionado. -- <a href="http://www.flickr.com/photos/travel_aficionado/2200003879/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/travel_aficionado/2200003879/</a>. -- Zugriff am 2009-01-08. -- <a href="http://creativecommons.org/licenses/by-nc/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielle Nutzung)]</p><blockquote><p>1 महामात्र m. &quot;Mahout&quot;; चरिष्णु 3 &quot;beweglich&quot;, दूरशब्द m. &quot;Ferngespräch, Fernsprecher&quot; » चरिष्णुदूरशब्द &quot;Mobiltelefon&quot; (Wortbildung: A. Payer)</p></blockquote><p>विभ्रम m.: das Hin- und Hergehen</p><p>भ्रंश m.: das Entfallen</p><p>श्रम् 4P श्राम्यति : sich abmühen, müde werden</p><blockquote><p>Perf. Vc शश्राम, शश्रामुर्<br> Fut. श्रमिष्यति<br> Pass. श्रम्यते<br> Kaus. श्रमयति । श्रामयति<br> PPP श्रान्त<br> Inf. श्रमितुम्<br> Absol. श्रमित्वा । श्रान्त्वा</p><p>davon:</p><p>आश्रम m.n.</p></blockquote><p><img src="'+u+'" alt=""><br> Abb.: श्रान्तः<br> Karnataka = ಕರ್ನಾಟಕ<br> [Bildquelle: mattlogelin. -- <a href="http://www.flickr.com/photos/mattlogelin/188588421/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/mattlogelin/188588421/</a>. -- Zugriff am 2009-01-09. -- <a href="http://creativecommons.org/licenses/by-nc/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielle Nutzung)]</p><p>श्रि 1U श्रयति : lehnen, sich anlehnen, Halt finden, sich zu jemandem begeben (द्वितीयया, सप्तम्या)</p><blockquote><p>Perf. IIIa शिश्राय, शिश्रिये<br> Fut. श्रयिष्यति<br> Pass. श्रीयते<br> Kaus. श्राययति<br> PPP श्रित<br> Inf. श्रयितुम्</p></blockquote><p>सञ्ज् 1P सजति : anhängen, sich heften an (सप्तम्या)</p><blockquote><p>Perf. I ससञ्ज, ससञ्जुर्<br> Fut. संक्ष्यति<br> Pass. सज्यते<br> Kaus. सञ्जयति<br> PPP सक्त<br> Inf. संक्तुम्</p><p>davon:</p><p>सङ्ग m.: das Anhängen an, Berührung mit (तृतीयया)</p></blockquote><p><img src="'+p+'" alt=""><br> Abb.: सङ्गः<br> Kamareddy = కామారెడ్డి<br> [Bildquelle: Sumanth K. Garakarajula. -- <a href="http://www.flickr.com/photos/photocracy1/2864457448/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/photocracy1/2864457448/</a>. -- Zugriff am 2009-01-09. -- <a href="http://creativecommons.org/licenses/by-nc/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielle Nutzung)]</p><p>द्रु 1P द्रवति : laufen, eilen</p><blockquote><p>Perf IIIa (अनिट्) दुद्राव, दुद्रुवुर्<br> Fut. द्रोष्यति<br> Pass. द्रूयते<br> Kaus. द्रावयति<br> PPP द्रुत<br> Inf. द्रोतुम्<br> Absol. -द्रुत्य</p></blockquote><p>भ्रम् 1P भ्रमति । 4P भ्राम्यति : umherirren, umherstreifen</p><blockquote><p>Perf. Vc बभ्राम, बभ्रमुर् । Vb भ्रेमुर्<br> Fut. भ्रमिष्यति<br> Kaus. भ्रमयति<br> PPP भ्रान्त<br> Inf. भ्रमितुम्<br> Absol. -भ्रम्य</p><p>davon:</p><p>विभ्रम m.: Umherirren, Verwirrung, Irrtum</p></blockquote><p>लम्ब् 1Ā लम्बते : herabhängen von (सप्तम्या), hängen an (सप्तम्या)</p><blockquote><p>Perf. I ललम्बे<br> Fut. लम्बिष्यते<br> Pass. लम्ब्यते<br> Kaus. लम्बयति<br> PPP लम्बित<br> Inf. लम्बितुम्<br> Absol. -लम्ब्य</p></blockquote><p><img src="'+c+'" alt=""><br> Abb.: लम्बोदर नमस्तुभ्यम्<br> उदरं लम्बते यस्य स लम्बोदरः (उदर n. &quot;Bauch&quot;)<br> गणेशचतुर्थी, Bangalore = ಬೆಂಗಳೂರು<br> [Bildquelle: mattlogelin. -- <a href="http://www.flickr.com/photos/mattlogelin/1397759461/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/mattlogelin/1397759461/</a>. -- Zugriff am 2009-01-08. -- <a href="http://creativecommons.org/licenses/by-nc/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielle Nutzung)]</p><p>लम्ब् + आ 1Ā आलम्बते : sich hängen an (द्वितीयया)</p><p>यदि Konjunktion:  wenn</p><p>भू + परि 1P परिभवति : einkreisen, bemeistern, besiegen</p><blockquote><p>PPP परिभूत 3: besiegt, gedemütigt, erniedrigt</p></blockquote><p>नि Präverb: niederwärts, hinunter, hinein, rückwärts</p><blockquote><p>z.B.</p><p>सद् + नि 1P निषीदति : sich niedersetzen</p></blockquote><p>भोस् Vokativpartikel: Ausruf der Anrede, z.B.: he, heda, oh, ei, hallo, hi! oft nicht zu übersetzen. Dieser Partikel hat einen Spezialsandhi: vor allen stimmhaften Lauten, lautet er भो.</p><p><img src="'+m+'" alt=""><br> Abb.: भोः<br> Kutch = कच्छ<br> [Bildquelle: orange tuesday. -- <a href="http://www.flickr.com/photos/63138333@N00/2162104243/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/63138333@N00/2162104243/</a>. -- Zugriff am 2009-01-09. --  <a href="http://creativecommons.org/licenses/by-nc/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielle Nutzung)]</p><h2 id="_46-3-ubung" tabindex="-1">46.3. Übung <a class="header-anchor" href="#_46-3-ubung" aria-label="Permalink to &quot;46.3. Übung&quot;">​</a></h2><p>A) Bestimmen und übersetzen Sie folgende Formen:</p><ol><li>वित्थ</li><li>वेत्थ</li><li>शिश्रियिढ्वे</li><li>शिश्ये</li><li>शिष्ये</li><li>चक्र</li><li>तुष्टुव</li><li>तुष्टम्</li><li>ददिथ</li><li>दत्थ</li><li>जग</li><li>जग्म</li><li>एनम्</li><li>ईय</li><li>निनेथ</li><li>शेक</li><li>सस्मर</li><li>पप्रष्ठ</li><li>दुग्ध</li><li>दुहितः</li><li>पेदिषे</li><li>ननर्त</li><li>ननृत</li><li>उवोढ</li><li>जुहोथ</li><li>जुहुथ</li><li>सक्तः</li><li>शक्तः</li><li>नेश्म</li><li>सोढुम्</li><li>ग्रहीष्ये</li><li>यत्ने</li><li>यते</li><li>बाले</li><li>ऊद</li><li>ऊदे</li><li>जज्ञिषे</li><li>चिक्य</li><li>अवेक्ष्य</li><li>वक्थ</li><li>शिष्ठ</li><li>पेचिथ</li><li>हथ</li><li>हस्त</li><li>ननन्द</li><li>श्राम्यसि</li><li>विषमम्</li><li>विशामः</li><li>उवस्थ</li><li>ददाने</li><li>सुषुपुः</li><li>ऊस</li></ol><p>B) Übersetzen Sie:</p><p>प्रजहाति यदा कामानात्मन्येवात्मना तुष्टः स्थितप्रज्ञस्तदोच्यते ॥१॥</p><blockquote><p>क्रोधाद्भवति संमोहः<br> संमोहात्स्मृतिविभ्रमः ।<br> स्मृतिभ्रंशाद्बुद्धिनाशो<br> बुद्धिनाशात्प्रनश्यति ॥२॥</p></blockquote><p>नास्ति बुद्धिरयुक्तस्य ॥३॥</p><p><img src="'+k+'" alt=""><br> Abb.: क्रोधाद्भवति संमोहः<br> संमोहात्स्मृतिविभ्रमः ।<br> स्मृतिभ्रंशाद्बुद्धिनाशो<br> बुद्धिनाशात्प्रनश्यति ॥<br> Mumbai = मुंबई nach dem Attentat, 11. Juli 2006<br> [Bildquelle: Sun Pictures / Lakshman. -- <a href="http://www.flickr.com/photos/lakshmananand/383843516/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/lakshmananand/383843516/</a>. -- Zugriff am 2009-01-09. --  <a href="http://creativecommons.org/licenses/by-nc-sa/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielle Nutzung, share alike)]</p>',148)])])}const S=e(f,[["render",g]]);export{I as __pageData,S as default};
